from typing import TypedDict


class CharacterProfile(TypedDict):
    name: str
    dynasty_or_period: str
    period_group: str
    tags: list[str]
    keywords: list[str]
    default_question: str
    suggested_questions: list[str]
    perspective: str
    featured: bool


def profile(
    name: str,
    dynasty_or_period: str,
    period_group: str,
    tags: list[str],
    keywords: list[str],
    default_question: str,
    suggested_questions: list[str],
    perspective: str,
    featured: bool = False,
) -> CharacterProfile:
    return {
        "name": name,
        "dynasty_or_period": dynasty_or_period,
        "period_group": period_group,
        "tags": tags,
        "keywords": keywords,
        "default_question": default_question,
        "suggested_questions": suggested_questions,
        "perspective": perspective,
        "featured": featured,
    }


